const input = $input.first().json;
const payload = input.body ?? input.payload ?? input;
const appSignature = $json["headers"]?.["x-app-signature"] ?? input.headers?.["x-app-signature"] ?? null;

return [{
  json: {
    ...input,
    payload,
    app_signature: appSignature,
    job_id: input.job_id ?? payload.job_id ?? payload?.job?.id,
    project_id: input.project_id ?? payload.project_id ?? payload?.project?.id,
    diagnosis_id: input.diagnosis_id ?? payload.diagnosis_id ?? payload?.diagnosis?.id,
    callback_url: input.callback_url ?? payload.callback_url,
    identify_drafts: input.identify_drafts ?? payload.identify_drafts ?? payload?.identify?.drafts ?? [],
    identify_merged: input.identify_merged ?? payload.identify_merged ?? payload?.identify?.merged ?? {}
  }
}];

const input = $input.first().json;

return [{
  json: {
    ...input,
    diagnosis_result: {
      primary_problem_type: 'qualified_traffic',
      secondary_problem_type: null,
      severity: 'high',
      confidence_score: 82,
      diagnosis_summary: 'Traffic intent is present but the content-to-query match is still weak.',
      root_cause: 'The site has useful content, but the pages are not aligned to a single search intent cluster yet.',
      evidence: [
        { label: 'Draft count', value: String((input.identify_drafts || []).length) },
        { label: 'Website stage', value: input.identify_merged?.website_stage ?? 'existing' }
      ],
      business_impact: {
        summary: 'Organic growth is being limited by intent mismatch and weak prioritization.',
        metrics: []
      },
      campaign_readiness: 'ready_with_cleanup',
      recommended_next_step: 'Define a target cluster and build one page per intent group.',
      objective_direction: 'qualified_traffic',
      not_recommended_actions: ['Publish more generic content without a cluster plan'],
      warnings: ['Review internal linking before scaling content volume'],
      raw_llm_output: {
        source: 'n8n-template',
        note: 'Replace this node with your AI or rules-based analysis.'
      },
      model_used: 'n8n-template'
    }
  }
}];

const body = JSON.stringify($input.first().json);
const timestamp = Math.floor(Date.now() / 1000);
const secret = $env.APP_WEBHOOK_SECRET;
const crypto = require('crypto');
const signature = crypto.createHmac('sha256', secret).update(`${timestamp}.${body}`).digest('hex');

return [{
  json: {
    ...$input.first().json,
    n8n_timestamp: String(timestamp),
    n8n_signature: signature
  }
}];

